// State
let selectedMonthIdx = monthsData.length - 1; // Default: latest month (Feb 2026)

// === Theme Toggle ===
(function() {
  const btn = document.querySelector('[data-theme-toggle]');
  const root = document.documentElement;
  let theme = matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  root.setAttribute('data-theme', theme);
  updateIcon();

  btn.addEventListener('click', () => {
    theme = theme === 'dark' ? 'light' : 'dark';
    root.setAttribute('data-theme', theme);
    updateIcon();
    createAllCharts();
  });

  function updateIcon() {
    btn.innerHTML = theme === 'dark'
      ? '<span class="material-symbols-outlined">light_mode</span>'
      : '<span class="material-symbols-outlined">dark_mode</span>';
  }
})();

// === Helpers ===
function fmt(n, decimals = 0) {
  if (n === undefined || n === null) return '—';
  return n.toLocaleString('de-DE', { minimumFractionDigits: decimals, maximumFractionDigits: decimals });
}
function fmtEur(n) { return '€' + fmt(n, 2); }

function getThemeColors() {
  const s = getComputedStyle(document.documentElement);
  return {
    text: s.getPropertyValue('--text').trim(),
    textSecondary: s.getPropertyValue('--text-secondary').trim(),
    textTertiary: s.getPropertyValue('--text-tertiary').trim(),
    border: s.getPropertyValue('--border-light').trim(),
    blue: s.getPropertyValue('--google-blue').trim(),
    red: s.getPropertyValue('--google-red').trim(),
    yellow: s.getPropertyValue('--google-yellow').trim(),
    green: s.getPropertyValue('--google-green').trim(),
    surface: s.getPropertyValue('--surface').trim(),
  };
}

// === Month Selector ===
function buildMonthSelector() {
  const container = document.getElementById('monthSelector');
  container.innerHTML = '';
  monthsData.forEach((m, i) => {
    const btn = document.createElement('button');
    btn.className = 'month-btn' + (i === selectedMonthIdx ? ' active' : '');
    btn.textContent = m.label;
    btn.addEventListener('click', () => {
      selectedMonthIdx = i;
      updateAll();
    });
    container.appendChild(btn);
  });
}

function updateAll() {
  buildMonthSelector();
  buildKPIs();
  buildTable();
  buildDoughnut();
}

// === Period Totals ===
function buildTotals() {
  const totalCost = monthsData.reduce((s, m) => s + m.cost, 0);
  const totalClicks = monthsData.reduce((s, m) => s + m.clicks, 0);
  const totalImpressions = monthsData.reduce((s, m) => s + m.impressions, 0);
  const totalConversions = monthsData.reduce((s, m) => s + m.conversions, 0);
  const avgCPA = totalConversions > 0 ? totalCost / totalConversions : 0;
  const avgCPC = totalClicks > 0 ? totalCost / totalClicks : 0;

  const items = [
    { label: 'Расходы', value: fmtEur(totalCost), color: 'blue' },
    { label: 'Конверсии', value: fmt(totalConversions), color: 'green' },
    { label: 'Ср. CPA', value: fmtEur(avgCPA), color: '' },
    { label: 'Клики', value: fmt(totalClicks), color: '' },
    { label: 'Показы', value: fmt(totalImpressions), color: '' },
    { label: 'Ср. CPC', value: fmtEur(avgCPC), color: '' },
  ];

  const bar = document.getElementById('totalsBar');
  bar.innerHTML = items.map(i => `
    <div class="totals-item">
      <div class="totals-item-label">${i.label}</div>
      <div class="totals-item-value${i.color ? ' color-' + i.color : ''}">${i.value}</div>
    </div>
  `).join('');
}

// === KPI Cards ===
function buildKPIs() {
  const current = monthsData[selectedMonthIdx];
  const prev = selectedMonthIdx > 0 ? monthsData[selectedMonthIdx - 1] : null;

  // Update section label
  const label = document.getElementById('kpiSectionLabel');
  if (prev) {
    label.textContent = current.fullName + ' vs ' + prev.fullName;
  } else {
    label.textContent = current.fullName;
  }

  function delta(curr, prevVal) {
    if (!prevVal || prevVal === 0) return { pct: 0, dir: 'flat' };
    const pct = ((curr - prevVal) / prevVal) * 100;
    return { pct, dir: pct > 0 ? 'up' : pct < 0 ? 'down' : 'flat' };
  }

  const kpis = [
    {
      label: 'Конверсии', icon: 'shopping_cart', value: fmt(current.conversions),
      delta: prev ? delta(current.conversions, prev.conversions) : null,
      sparkData: monthsData.map(m => m.conversions), color: 'blue'
    },
    {
      label: 'CPA', icon: 'paid', value: fmtEur(current.cpa),
      delta: prev ? delta(current.cpa, prev.cpa) : null,
      sparkData: monthsData.map(m => m.cpa), color: 'green',
      invertDelta: true
    },
    {
      label: 'Расходы', icon: 'account_balance_wallet', value: fmtEur(current.cost),
      delta: prev ? delta(current.cost, prev.cost) : null,
      sparkData: monthsData.map(m => m.cost), color: 'yellow'
    },
    {
      label: 'Клики', icon: 'ads_click', value: fmt(current.clicks),
      delta: prev ? delta(current.clicks, prev.clicks) : null,
      sparkData: monthsData.map(m => m.clicks), color: 'blue'
    },
    {
      label: 'Показы', icon: 'visibility', value: fmt(current.impressions),
      delta: prev ? delta(current.impressions, prev.impressions) : null,
      sparkData: monthsData.map(m => m.impressions), color: 'red'
    },
    {
      label: 'Ср. CPC', icon: 'touch_app', value: fmtEur(current.cpc),
      delta: prev ? delta(current.cpc, prev.cpc) : null,
      sparkData: monthsData.map(m => m.cpc), color: 'green',
      invertDelta: true
    },
  ];

  const grid = document.getElementById('kpiGrid');
  grid.innerHTML = '';

  kpis.forEach(kpi => {
    const d = kpi.delta;
    let dirClass = 'flat';
    let arrow = 'remove';
    let pctText = '';

    if (d) {
      dirClass = d.dir;
      if (kpi.invertDelta) {
        dirClass = d.dir === 'up' ? 'down' : d.dir === 'down' ? 'up' : 'flat';
      }
      arrow = d.dir === 'up' ? 'arrow_upward' : d.dir === 'down' ? 'arrow_downward' : 'remove';
      pctText = Math.abs(d.pct).toFixed(1) + '%';
    }

    const card = document.createElement('div');
    card.className = 'kpi-card';
    card.innerHTML = `
      <div class="kpi-label">
        <span class="material-symbols-outlined">${kpi.icon}</span>
        ${kpi.label}
      </div>
      <div class="kpi-value color-${kpi.color}">${kpi.value}</div>
      ${d ? `<div class="kpi-delta ${dirClass}">
        <span class="material-symbols-outlined">${arrow}</span>
        ${pctText}
      </div>` : ''}
      <canvas class="kpi-sparkline" data-spark="${kpi.color}"></canvas>
    `;
    grid.appendChild(card);

    const canvas = card.querySelector('.kpi-sparkline');
    drawSparkline(canvas, kpi.sparkData, kpi.color, selectedMonthIdx);
  });
}

function drawSparkline(canvas, data, colorKey, highlightIdx) {
  const ctx = canvas.getContext('2d');
  const rect = canvas.parentElement.getBoundingClientRect();
  canvas.width = rect.width * 2;
  canvas.height = 80;
  const w = canvas.width;
  const h = canvas.height;
  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min || 1;

  const colors = { blue: '#1a73e8', red: '#ea4335', yellow: '#fbbc04', green: '#34a853' };
  const c = colors[colorKey] || colors.blue;

  ctx.beginPath();
  data.forEach((v, i) => {
    const x = (i / (data.length - 1)) * w;
    const y = h - ((v - min) / range) * h * 0.8 - h * 0.1;
    if (i === 0) ctx.moveTo(x, y);
    else ctx.lineTo(x, y);
  });

  ctx.lineTo(w, h);
  ctx.lineTo(0, h);
  ctx.closePath();
  ctx.fillStyle = c;
  ctx.globalAlpha = 0.5;
  ctx.fill();
  ctx.globalAlpha = 1;

  // Highlight dot for selected month
  if (highlightIdx !== undefined) {
    const x = (highlightIdx / (data.length - 1)) * w;
    const y = h - ((data[highlightIdx] - min) / range) * h * 0.8 - h * 0.1;
    ctx.beginPath();
    ctx.arc(x, y, 6, 0, Math.PI * 2);
    ctx.fillStyle = c;
    ctx.globalAlpha = 1;
    ctx.fill();
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 2;
    ctx.stroke();
  }
}

// === Charts ===
let chartInstances = {};

function destroyCharts() {
  Object.values(chartInstances).forEach(c => c.destroy());
  chartInstances = {};
}

function createAllCharts() {
  destroyCharts();
  const tc = getThemeColors();
  const labels = monthsData.map(m => m.label);

  Chart.defaults.font.family = "'Roboto', 'Segoe UI', sans-serif";
  Chart.defaults.color = tc.textSecondary;

  const gridColor = tc.border;
  const gridOpts = { color: gridColor, drawBorder: false };
  const xOpts = { grid: { display: false }, ticks: { font: { size: 11 }, maxRotation: 45, minRotation: 0 } };

  const tooltipOpts = {
    backgroundColor: tc.surface,
    titleColor: tc.text,
    bodyColor: tc.textSecondary,
    borderColor: tc.border,
    borderWidth: 1,
    cornerRadius: 8,
    padding: 12,
  };

  // Highlight selected bar
  function highlightBars(baseColor, count) {
    return Array.from({ length: count }, (_, i) => i === selectedMonthIdx ? baseColor : baseColor + '44');
  }

  // 1. Cost & Conversions
  chartInstances.costConv = new Chart(document.getElementById('chartCostConv'), {
    type: 'bar',
    data: {
      labels,
      datasets: [
        {
          label: 'Расходы (€)',
          data: monthsData.map(m => m.cost),
          backgroundColor: highlightBars(tc.blue, monthsData.length),
          borderColor: tc.blue,
          borderWidth: 1,
          borderRadius: 4,
          order: 2,
          yAxisID: 'y',
        },
        {
          label: 'Конверсии',
          data: monthsData.map(m => m.conversions),
          type: 'line',
          borderColor: tc.green,
          backgroundColor: tc.green,
          pointBackgroundColor: monthsData.map((_, i) => i === selectedMonthIdx ? tc.green : tc.green + '88'),
          pointRadius: monthsData.map((_, i) => i === selectedMonthIdx ? 6 : 3),
          pointHoverRadius: 6,
          borderWidth: 2.5,
          tension: 0.3,
          order: 1,
          yAxisID: 'y1',
        }
      ]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      interaction: { mode: 'index', intersect: false },
      onClick: (e, elements) => {
        if (elements.length > 0) {
          selectedMonthIdx = elements[0].index;
          updateAll();
          createAllCharts();
        }
      },
      plugins: {
        legend: { position: 'top', align: 'end', labels: { usePointStyle: true, pointStyle: 'rectRounded', padding: 16, font: { size: 12 } } },
        tooltip: { ...tooltipOpts,
          callbacks: {
            label: (ctx) => ctx.dataset.label === 'Расходы (€)'
              ? `Расходы: €${ctx.raw.toLocaleString('de-DE', {minimumFractionDigits: 2})}`
              : `Конверсии: ${ctx.raw}`
          }
        }
      },
      scales: {
        x: xOpts,
        y: { position: 'left', grid: gridOpts, ticks: { font: { size: 11 }, callback: v => '€' + (v >= 1000 ? (v/1000).toFixed(1) + 'K' : v) }, beginAtZero: true },
        y1: { position: 'right', grid: { display: false }, ticks: { font: { size: 11 } }, beginAtZero: true }
      }
    }
  });
  document.getElementById('chartCostConv').parentElement.style.height = '320px';

  // 2. CPA over time
  chartInstances.cpa = new Chart(document.getElementById('chartCPA'), {
    type: 'line',
    data: {
      labels,
      datasets: [{ label: 'CPA (€)', data: monthsData.map(m => m.cpa), borderColor: tc.green, backgroundColor: tc.green + '1a', pointBackgroundColor: monthsData.map((_, i) => i === selectedMonthIdx ? tc.green : tc.green + '88'), pointRadius: monthsData.map((_, i) => i === selectedMonthIdx ? 6 : 3), pointHoverRadius: 6, borderWidth: 2.5, tension: 0.3, fill: true }]
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      onClick: (e, elements) => { if (elements.length > 0) { selectedMonthIdx = elements[0].index; updateAll(); createAllCharts(); } },
      plugins: { legend: { display: false }, tooltip: { ...tooltipOpts, callbacks: { label: (ctx) => `CPA: €${ctx.raw.toFixed(2)}` } } },
      scales: { x: xOpts, y: { grid: gridOpts, ticks: { font: { size: 11 }, callback: v => '€' + v }, beginAtZero: true } }
    }
  });
  document.getElementById('chartCPA').parentElement.style.height = '280px';

  // 3. Clicks
  chartInstances.clicks = new Chart(document.getElementById('chartClicks'), {
    type: 'bar',
    data: {
      labels,
      datasets: [{ label: 'Клики', data: monthsData.map(m => m.clicks), backgroundColor: highlightBars(tc.blue, monthsData.length), borderRadius: 4 }]
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      onClick: (e, elements) => { if (elements.length > 0) { selectedMonthIdx = elements[0].index; updateAll(); createAllCharts(); } },
      plugins: { legend: { display: false }, tooltip: tooltipOpts },
      scales: { x: xOpts, y: { grid: gridOpts, ticks: { font: { size: 11 }, callback: v => v >= 1000 ? (v/1000).toFixed(1) + 'K' : v }, beginAtZero: true } }
    }
  });
  document.getElementById('chartClicks').parentElement.style.height = '280px';

  // 4. Impressions
  chartInstances.impressions = new Chart(document.getElementById('chartImpressions'), {
    type: 'line',
    data: {
      labels,
      datasets: [{ label: 'Показы', data: monthsData.map(m => m.impressions), borderColor: tc.red, backgroundColor: tc.red + '1a', pointBackgroundColor: monthsData.map((_, i) => i === selectedMonthIdx ? tc.red : tc.red + '88'), pointRadius: monthsData.map((_, i) => i === selectedMonthIdx ? 6 : 3), pointHoverRadius: 6, borderWidth: 2.5, tension: 0.3, fill: true }]
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      onClick: (e, elements) => { if (elements.length > 0) { selectedMonthIdx = elements[0].index; updateAll(); createAllCharts(); } },
      plugins: { legend: { display: false }, tooltip: { ...tooltipOpts, callbacks: { label: (ctx) => `Показы: ${ctx.raw.toLocaleString('de-DE')}` } } },
      scales: { x: xOpts, y: { grid: gridOpts, ticks: { font: { size: 11 }, callback: v => v >= 1000 ? (v/1000).toFixed(0) + 'K' : v }, beginAtZero: true } }
    }
  });
  document.getElementById('chartImpressions').parentElement.style.height = '280px';

  // 5. CPC
  chartInstances.cpc = new Chart(document.getElementById('chartCPC'), {
    type: 'line',
    data: {
      labels,
      datasets: [{ label: 'Ср. CPC (€)', data: monthsData.map(m => m.cpc), borderColor: tc.yellow, backgroundColor: tc.yellow + '1a', pointBackgroundColor: monthsData.map((_, i) => i === selectedMonthIdx ? tc.yellow : tc.yellow + '88'), pointRadius: monthsData.map((_, i) => i === selectedMonthIdx ? 6 : 3), pointHoverRadius: 6, borderWidth: 2.5, tension: 0.3, fill: true }]
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      onClick: (e, elements) => { if (elements.length > 0) { selectedMonthIdx = elements[0].index; updateAll(); createAllCharts(); } },
      plugins: { legend: { display: false }, tooltip: { ...tooltipOpts, callbacks: { label: (ctx) => `CPC: €${ctx.raw.toFixed(2)}` } } },
      scales: { x: xOpts, y: { grid: gridOpts, ticks: { font: { size: 11 }, callback: v => '€' + v.toFixed(2) }, beginAtZero: true } }
    }
  });
  document.getElementById('chartCPC').parentElement.style.height = '280px';
}

// === Doughnut (per selected month) ===
let doughnutChart = null;
function buildDoughnut() {
  if (doughnutChart) doughnutChart.destroy();
  const tc = getThemeColors();
  const current = monthsData[selectedMonthIdx];
  const campaigns = current.campaigns.filter(c => c.cost > 0);
  const totalCost = campaigns.reduce((s, c) => s + c.cost, 0);

  // Short labels
  const shortLabels = campaigns.map(c => {
    if (c.name.length > 20) return c.name.slice(0, 18) + '...';
    return c.name;
  });

  const colors = [tc.blue, tc.red, tc.yellow, tc.green, '#a855f7', '#f97316', '#06b6d4', '#84cc16'];

  // Update title
  document.getElementById('doughnutTitle').textContent = 'Распределение бюджета (' + current.label + ')';

  doughnutChart = new Chart(document.getElementById('chartBudget'), {
    type: 'doughnut',
    data: {
      labels: shortLabels,
      datasets: [{ data: campaigns.map(c => c.cost), backgroundColor: colors.slice(0, campaigns.length), borderColor: tc.surface, borderWidth: 3, hoverOffset: 6 }]
    },
    options: {
      responsive: true, maintainAspectRatio: true, cutout: '65%',
      plugins: {
        legend: { position: 'bottom', labels: { usePointStyle: true, pointStyle: 'rectRounded', padding: 10, font: { size: 11 } } },
        tooltip: {
          backgroundColor: tc.surface, titleColor: tc.text, bodyColor: tc.textSecondary, borderColor: tc.border, borderWidth: 1, cornerRadius: 8, padding: 12,
          callbacks: { label: (ctx) => `€${ctx.raw.toFixed(2)} (${((ctx.raw / totalCost) * 100).toFixed(1)}%)` }
        }
      }
    }
  });
}

// === Table (per selected month) ===
function buildTable() {
  const current = monthsData[selectedMonthIdx];
  const campaigns = current.campaigns;

  // Update title
  document.getElementById('tableTitle').textContent = 'Детализация по кампаниям — ' + current.fullName;

  const body = document.getElementById('campaignBody');
  body.innerHTML = '';

  const typeMap = { 'Поиск': 'search', 'PMax': 'pmax', 'КМС': 'display', 'Баннеры': 'display' };

  campaigns.forEach(c => {
    const cls = typeMap[c.type] || 'search';
    const tr = document.createElement('tr');
    tr.innerHTML = `
      <td class="name">${c.name}</td>
      <td><span class="campaign-type type-${cls}">${c.type}</span></td>
      <td class="num">${fmt(c.clicks)}</td>
      <td class="num">${fmt(c.impressions)}</td>
      <td class="num">${c.ctr.toFixed(2)}%</td>
      <td class="num">${fmtEur(c.cpc)}</td>
      <td class="num">${fmtEur(c.cost)}</td>
      <td class="num">${c.conversions > 0 ? fmt(c.conversions) : '—'}</td>
      <td class="num">${c.cpa > 0 ? fmtEur(c.cpa) : '—'}</td>
    `;
    body.appendChild(tr);
  });

  // Totals
  const totals = {
    clicks: campaigns.reduce((s, c) => s + c.clicks, 0),
    impressions: campaigns.reduce((s, c) => s + c.impressions, 0),
    cost: campaigns.reduce((s, c) => s + c.cost, 0),
    conversions: campaigns.reduce((s, c) => s + c.conversions, 0),
  };
  const totalCPA = totals.conversions > 0 ? totals.cost / totals.conversions : 0;
  const totalCPC = totals.clicks > 0 ? totals.cost / totals.clicks : 0;
  const totalCTR = totals.impressions > 0 ? (totals.clicks / totals.impressions) * 100 : 0;

  const tr = document.createElement('tr');
  tr.style.fontWeight = '700';
  tr.style.borderTop = '2px solid var(--border)';
  tr.innerHTML = `
    <td class="name">Итого</td>
    <td></td>
    <td class="num">${fmt(totals.clicks)}</td>
    <td class="num">${fmt(totals.impressions)}</td>
    <td class="num">${totalCTR.toFixed(2)}%</td>
    <td class="num">${fmtEur(totalCPC)}</td>
    <td class="num">${fmtEur(totals.cost)}</td>
    <td class="num">${fmt(totals.conversions)}</td>
    <td class="num">${totalCPA > 0 ? fmtEur(totalCPA) : '—'}</td>
  `;
  body.appendChild(tr);
}

// === Work Items ===
function buildWorkList() {
  const list = document.getElementById('workList');
  list.innerHTML = '';
  workItems.forEach(item => {
    const li = document.createElement('li');
    li.className = 'work-item';
    li.innerHTML = `<span class="material-symbols-outlined">check_circle</span>${item}`;
    list.appendChild(li);
  });
}

